import React, { useContext, useState } from "react";
import { useShoppingCart } from "../contexts/CartContext";


const Cart = () => {
  const { cartItems, removeItemFromCart, clearCart, totalPrice, updateItemQuantity, totalItems } = useShoppingCart();

  return (
    <div className="container mx-auto p-6">
      {cartItems.length > 0 ? (
        <>
          <h2 className="text-3xl font-bold mb-6 text-center">Your Shopping Cart ({totalItems} {totalItems === 1 ? `item`: `items`})</h2>
          <ul className="space-y-4">
            {cartItems.map((item) => (
              <li
                key={item.id}
                className="flex items-center justify-between border-b pb-4">
                <div className="flex items-center space-x-4">
                  <img
                    src={item.thumbnail}
                    alt={item.title}
                    className="w-auto h-full object-cover rounded-md"
                  />
                  <div>
                    <h3 className="text-lg font-semibold">{item.title}</h3>
                    <p className="text-gray-600 w-1/2">{item.description}</p>
                    <p className="text-sm text-gray-500">Price: ${item.price}</p>
                  </div>
                </div>
                <div className="text-center">
                  <div className="flex items-center space-x-2 mb-2">
                    <button
                      onClick={() => updateItemQuantity(item.id, item.quantity - 1)}
                      disabled={item.quantity === 1}
                      className={`px-3 py-1 bg-gray-200 rounded ${item.quantity === 1
                        ? "cursor-not-allowed opacity-50"
                        : "hover:bg-gray-300"
                        }`}
                    >
                      -
                    </button>
                    <span className="font-semibold text-lg">{item.quantity}</span>
                    <button
                      onClick={() => updateItemQuantity(item.id, item.quantity + 1)}
                      className="px-3 py-1 bg-blue-500 text-white rounded hover:bg-blue-600"
                    >
                      +
                    </button>
                  </div>
                  <button
                    onClick={() => removeItemFromCart(item.id)}
                    className="text-red-500 hover:underline text-sm"
                  >
                    Remove
                  </button>
                </div>
              </li>
            ))}
          </ul>
          <div className="mt-8 flex justify-between items-center">
            <p className="text-xl font-bold">Subtotal: ${totalPrice.toFixed(2)}</p>
            <button
              type="submit"
              className="bg-blue-600 text-white px-6 py-3 rounded hover:bg-blue-700"
            >
              Go to Checkout
            </button>
          </div>
          <p className="text-sm text-gray-500 mt-2 text-center">
            Taxes and shipping are calculated at checkout.
          </p>
        </>
      ) : (
        <p className="text-center text-gray-600">Your cart is empty.</p>
      )}
    </div>
  );
};

export default Cart;
